22	// ReviewSession is the server-side review state machine persisted under
23	// .ddx/reviews/<session-id>/ for Story 16 and review mutations.
24	//
25	// Story 16 on-disk contract:
26	//   - manifest.json stores the session metadata only: id, artifact refs,
27	//     rubric/template/prompt refs, status, and billing limits.
28	//   - turns.jsonl is append-only JSONL. Each non-empty line is one ReviewTurn
29	//     record with actor, content, cost_usd, and created_at.
30	//   - attachments/ stores any binary sidecar files for the session.
31	//
32	// The manifest is written when a session is created. Turns are appended
33	// without rewriting prior lines so the review transcript remains durable and
34	// streamable.
35	type ReviewSession struct {
36		ID             string       `json:"id"`
37		ArtifactID     string       `json:"artifact_id"`
38		ArtifactSHA    string       `json:"artifact_sha"`
39		ArtifactGitRev string       `json:"artifact_git_rev"`
40		SystemRubric   string       `json:"system_rubric"`
41		TemplateRef    string       `json:"template_ref"`
42		PromptRef      string       `json:"prompt_ref"`
43		Status         string       `json:"status"`
44		Turns          []ReviewTurn `json:"turns,omitempty"`
45		CostUSD        float64      `json:"cost_usd"`
46		MaxBillableUSD float64      `json:"max_billable_usd"`
47	}
48	
49	// ReviewTurn is one append-only transcript entry in turns.jsonl.
50	type ReviewTurn struct {
51		Actor     string    `json:"actor"`
52		Content   string    `json:"content"`
53		CostUSD   float64   `json:"cost_usd"`
54		CreatedAt time.Time `json:"created_at"`
55	}
