62		SystemRubric   string  `json:"system_rubric"`
63		TemplateRef    string  `json:"template_ref"`
64		PromptRef      string  `json:"prompt_ref"`
65		Status         string  `json:"status"`
66		CostUSD        float64 `json:"cost_usd"`
67		MaxBillableUSD float64 `json:"max_billable_usd"`
68	}
