138	// Load reads the manifest plus append-only transcript back into memory.
139	func (s *ReviewSessionStore) Load(sessionID string) (*ReviewSession, error) {
140		if s == nil {
141			return nil, errors.New("review session store: nil store")
142		}
143		root, err := s.sessionRoot(sessionID)
144		if err != nil {
145			return nil, err
146		}
147	
148		data, err := os.ReadFile(filepath.Join(root, reviewManifestName))
149		if err != nil {
150			return nil, fmt.Errorf("review session: read manifest: %w", err)
151		}
152		var manifest reviewSessionManifest
153		if err := json.Unmarshal(data, &manifest); err != nil {
154			return nil, fmt.Errorf("review session: parse manifest: %w", err)
155		}
156		session := &ReviewSession{
157			ID:             manifest.ID,
158			ArtifactID:     manifest.ArtifactID,
159			ArtifactSHA:    manifest.ArtifactSHA,
160			ArtifactGitRev: manifest.ArtifactGitRev,
161			SystemRubric:   manifest.SystemRubric,
162			TemplateRef:    manifest.TemplateRef,
163			PromptRef:      manifest.PromptRef,
164			Status:         manifest.Status,
165			CostUSD:        manifest.CostUSD,
166			MaxBillableUSD: manifest.MaxBillableUSD,
167		}
168	
169		turnsPath := filepath.Join(root, reviewTurnsName)
170		f, err := os.Open(turnsPath)
171		if err != nil {
172			if os.IsNotExist(err) {
173				return session, nil
174			}
175			return nil, fmt.Errorf("review session: read turns: %w", err)
176		}
177		defer f.Close()
178	
179		scanner := bufio.NewScanner(f)
180		scanner.Buffer(make([]byte, 0, 64*1024), 8*1024*1024)
181		for scanner.Scan() {
182			line := strings.TrimSpace(scanner.Text())
183			if line == "" {
184				continue
185			}
186			var turn ReviewTurn
187			if err := json.Unmarshal([]byte(line), &turn); err != nil {
188				return nil, fmt.Errorf("review session: parse turn: %w", err)
189			}
190			session.Turns = append(session.Turns, turn)
191		}
192		if err := scanner.Err(); err != nil {
193			return nil, fmt.Errorf("review session: scan turns: %w", err)
194		}
195		return session, nil
196	}
