9	// TestReviewMaxRetriesConfig covers FEAT-022 §14: the review_max_retries
10	// field in .ddx/config.yaml overrides the binary default (3) used by the
11	// execute-loop's bounded reviewer-retry policy. Verified end-to-end: the
12	// YAML loader populates the field, the resolver returns the override, and
13	// the loop respects it via the same accessor (DefaultReviewMaxRetries
14	// constant in cli/internal/agent kept in sync with this default).
15	func TestReviewMaxRetriesConfig(t *testing.T) {
16		t.Run("default_when_unset", func(t *testing.T) {
17			c := &NewConfig{Version: "1.0"}
18			if got := c.ResolveReviewMaxRetries(); got != 3 {
19				t.Errorf("default ResolveReviewMaxRetries = %d, want 3", got)
20			}
21		})
22	
23		t.Run("default_when_zero_or_negative", func(t *testing.T) {
24			zero := 0
25			neg := -7
26			for _, v := range []*int{&zero, &neg} {
27				c := &NewConfig{Version: "1.0", ReviewMaxRetries: v}
28				if got := c.ResolveReviewMaxRetries(); got != 3 {
29					t.Errorf("non-positive ReviewMaxRetries (%d) should fall back to 3, got %d", *v, got)
30				}
31			}
32		})
33	
34		t.Run("override_loaded_from_yaml", func(t *testing.T) {
35			tmp := t.TempDir()
36			if err := os.MkdirAll(filepath.Join(tmp, ".ddx"), 0o755); err != nil {
37				t.Fatal(err)
38			}
39			yaml := `version: "1.0"
40	library:
41	  path: .ddx/plugins/ddx
42	  repository:
43	    url: https://github.com/DocumentDrivenDX/ddx-library
44	    branch: main
45	review_max_retries: 5
46	`
47			if err := os.WriteFile(filepath.Join(tmp, ".ddx", "config.yaml"), []byte(yaml), 0o600); err != nil {
48				t.Fatal(err)
49			}
50			loader, err := NewConfigLoaderWithWorkingDir(tmp)
51			if err != nil {
52				t.Fatal(err)
53			}
54			cfg, err := loader.LoadConfig()
55			if err != nil {
56				t.Fatal(err)
57			}
58			if cfg.ReviewMaxRetries == nil {
59				t.Fatal("ReviewMaxRetries was not populated from YAML")
60			}
61			if *cfg.ReviewMaxRetries != 5 {
62				t.Errorf("loaded ReviewMaxRetries = %d, want 5", *cfg.ReviewMaxRetries)
63			}
64			if got := cfg.ResolveReviewMaxRetries(); got != 5 {
65				t.Errorf("ResolveReviewMaxRetries = %d, want 5 (override must reach the loop)", got)
66			}
67		})
68	}
