198	func (s *ReviewSessionStore) sessionRoot(sessionID string) (string, error) {
199		if s == nil {
200			return "", errors.New("review session store: nil store")
201		}
202		if s.projectRoot == "" {
203			return "", errors.New("review session store: empty project root")
204		}
205		if sessionID == "" {
206			return "", errors.New("review session store: empty session id")
207		}
208		if sessionID == "." || sessionID == ".." || strings.ContainsAny(sessionID, "/\\") {
209			return "", fmt.Errorf("review session store: invalid session id %q", sessionID)
210		}
211		return filepath.Join(s.projectRoot, ".ddx", reviewSessionsDirName, sessionID), nil
212	}
