364	func runPreCloseReviewGroup(ctx context.Context, reviewer BeadReviewer, beadID, resultRev string, impl ImplementerRouting) (*ReviewGroupResult, error) {
365		if reviewer == nil {
366			return nil, fmt.Errorf("review-group: reviewer required")
367		}
368		if groupReviewer, ok := reviewer.(reviewGroupReviewer); ok {
369			return groupReviewer.ReviewGroup(ctx, beadID, resultRev, impl)
370		}
371		result, err := reviewer.ReviewBead(ctx, beadID, resultRev, impl)
372		group := &ReviewGroupResult{
373			BeadID:    beadID,
374			ResultRev: resultRev,
375			Slots: []ReviewGroupSlotResult{
376				{
377					ReviewerIndex: 0,
378					Result:        result,
379				},
380			},
381		}
382		if err != nil {
383			group.Slots[0].Error = err.Error()
384		}
385		return group, err
386	}
