388	func reviewErrorReviewerIndex(group *ReviewGroupResult, res *ReviewResult) (int, bool) {
389		if group == nil || len(group.Slots) < 2 {
390			return 0, false
391		}
392		if res != nil {
393			for _, slot := range group.Slots {
394				if slot.Result == res {
395					return slot.ReviewerIndex, true
396				}
397			}
398			return res.ReviewerIndex, true
399		}
400		for _, slot := range group.Slots {
401			if slot.Error != "" {
402				return slot.ReviewerIndex, true
403			}
404		}
405		return 0, true
406	}
