408	func reducePreCloseReviewGroup(group *ReviewGroupResult) (*ReviewResult, error) {
409		if group == nil || len(group.Slots) == 0 {
410			return nil, fmt.Errorf("review-group: no review slots")
411		}
412		var firstApprove *ReviewResult
413		var firstNonApprove *ReviewResult
414		var firstResult *ReviewResult
415		for _, slot := range group.Slots {
416			if slot.Result != nil && firstResult == nil {
417				firstResult = slot.Result
418			}
419			if slot.Error != "" && slot.Result == nil {
420				if firstResult != nil {
421					return firstResult, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
422				}
423				return nil, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
424			}
425			if slot.Result == nil {
426				if firstResult != nil {
427					return firstResult, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
428				}
429				return nil, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
430			}
431			res := slot.Result
432			switch res.Verdict {
433			case VerdictApprove:
434				if !reviewResultHasACEvidence(res) {
435					return res, fmt.Errorf("%w: approve verdict without per-AC evidence", ErrReviewVerdictUnparseable)
436				}
437				if firstApprove == nil {
438					firstApprove = res
439				}
440			case VerdictRequestChanges, VerdictBlock:
441				if firstNonApprove == nil {
442					firstNonApprove = res
443				}
444			default:
445				if firstNonApprove == nil {
446					firstNonApprove = res
447				}
448			}
449		}
450		if firstNonApprove != nil {
451			return firstNonApprove, nil
452		}
453		return firstApprove, nil
454	}
