456	func reviewResultHasACEvidence(res *ReviewResult) bool {
457		if res == nil || res.Verdict != VerdictApprove {
458			return false
459		}
460		if len(res.PerAC) == 0 {
461			return false
462		}
463		for _, ac := range res.PerAC {
464			if strings.TrimSpace(ac.Evidence) == "" {
465				return false
466			}
467		}
468		return true
469	}
