471	// applyReviewTriageDecision runs the triage policy after a BLOCK or
472	// REQUEST_CHANGES review verdict has been recorded for `beadID`. It reads
473	// prior review events to compute the BLOCK count, biases the result toward
474	// re-attempt when the latest BLOCK was paired with a degraded reviewer
475	// (kind:review-pairing-degraded), then applies the chosen action by writing
476	// metadata, labels, and a kind:triage-decision event.
477	//
478	// Errors from the underlying store are best-effort: callers continue
479	// regardless so a triage-side failure cannot strand a bead in an
480	// inconsistent review state. This callout previously lived as a method on
481	// ExecuteBeadWorker; the C3
482	// extraction (ddx-a921ff01) moves it inside the post-merge-review pipeline
483	// driven by RunPostMergeReview / try.Attempt.
484	func applyReviewTriageDecision(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, currentTier string) error {
485		events, err := store.Events(beadID)
486		if err != nil {
487			return err
488		}
489	
490		var blockTimestamps []time.Time
491		var pairingDegraded []time.Time
492		for _, ev := range events {
493			switch {
494			case ev.Kind == "review" && strings.TrimSpace(ev.Summary) == "BLOCK":
495				blockTimestamps = append(blockTimestamps, ev.CreatedAt)
496			case ev.Kind == ReviewPairingDegradedEventKind:
497				pairingDegraded = append(pairingDegraded, ev.CreatedAt)
498			}
499		}
500	
501		// History excludes the current attempt. The just-appended BLOCK (if any)
502		// is the last entry in blockTimestamps and must not be counted as prior
503		// history per triage.Decide()'s contract.
504		historyCount := len(blockTimestamps)
505		if historyCount > 0 {
506			historyCount--
507		}
508		history := make([]triage.FailureMode, 0, historyCount)
509		for i := 0; i < historyCount; i++ {
510			history = append(history, triage.FailureModeReviewBlock)
511		}
512	
513		policy := triage.DefaultPolicy()
514		action := policy.Decide(beadID, triage.FailureModeReviewBlock, history)
515	
516		pairedDegraded := latestBlockPairedDegraded(blockTimestamps, pairingDegraded)
517		if pairedDegraded && action == triage.ActionEscalateTier {
518			action = triage.ActionReAttemptWithContext
519		}
520	
521		return applyTriageAction(store, beadID, actor, now, action, currentTier, pairedDegraded)
522	}
