524	// latestBlockPairedDegraded reports whether the most recent BLOCK event was
525	// paired with a review-pairing-degraded event from the same attempt window
526	// (between the previous BLOCK and this one).
527	func latestBlockPairedDegraded(blocks, pairing []time.Time) bool {
528		if len(blocks) == 0 || len(pairing) == 0 {
529			return false
530		}
531		latest := blocks[len(blocks)-1]
532		var prev time.Time
533		if len(blocks) >= 2 {
534			prev = blocks[len(blocks)-2]
535		}
536		for _, t := range pairing {
537			if t.After(prev) && !t.After(latest) {
538				return true
539			}
540		}
541		return false
542	}
