544	// applyTriageAction performs the side effects for a chosen Action: writes a
545	// tier-pin hint into bead.Extra (escalate_tier), moves the bead to proposed
546	// for operator-required outcomes, and always records a triage-decision event.
547	func applyTriageAction(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, action triage.Action, currentTier string, pairedDegraded bool) error {
548		body := map[string]any{
