612	// nextEscalatedTier returns the next tier above `current`. An unrecognised or
613	// empty current tier defaults to standard; smart is its own ceiling.
614	func nextEscalatedTier(current string) escalation.ModelTier {
615		switch escalation.ModelTier(current) {
616		case escalation.TierCheap:
617			return escalation.TierStandard
618		case escalation.TierStandard:
619			return escalation.TierSmart
620		case escalation.TierSmart:
621			return escalation.TierSmart
622		default:
623			return escalation.TierStandard
624		}
