3081	//     (the reviewer set it explicitly — preferred path).
3082	//  2. The error string text (for backwards-compatible reviewers that only
3083	//     embed the class in their message).
3084	//  3. ErrReviewVerdictUnparseable as a fallback when the strict-parse error
3085	//     leaks through a reviewer that did not set Error.
3086	//  4. Default to transport (network/provider-side failure) when nothing else
3087	//     matches.
3088	func ClassifyReviewError(reviewErr error, reviewRes *ReviewResult) string {
3089		if reviewRes != nil {
3090			switch reviewRes.Error {
3091			case evidence.OutcomeReviewContextOverflow,
3092				evidence.OutcomeReviewProviderEmpty,
3093				evidence.OutcomeReviewUnparseable,
3094				evidence.OutcomeReviewTransport:
3095				return reviewRes.Error
3096			}
3097		}
3098		msg := ""
3099		if reviewErr != nil {
3100			msg = reviewErr.Error()
3101		}
3102		switch {
3103		case strings.Contains(msg, evidence.OutcomeReviewContextOverflow):
3104			return evidence.OutcomeReviewContextOverflow
3105		case strings.Contains(msg, evidence.OutcomeReviewProviderEmpty):
3106			return evidence.OutcomeReviewProviderEmpty
3107		case strings.Contains(msg, evidence.OutcomeReviewUnparseable):
3108			return evidence.OutcomeReviewUnparseable
3109		case strings.Contains(msg, evidence.OutcomeReviewTransport):
3110			return evidence.OutcomeReviewTransport
3111		case reviewErr != nil && strings.Contains(msg, ErrReviewVerdictUnparseable.Error()):
3112			return evidence.OutcomeReviewUnparseable
3113		}
3114		return evidence.OutcomeReviewTransport
3115	}
