3117	// reResultRevField extracts the result_rev value from a structured review-error
3118	// event body (one `result_rev=<sha>` line per event, written by
3119	// reviewErrorEventBody). The format is intentionally line-oriented so it
3120	// survives the AppendEvent body cap without losing the rev association.
3121	var reResultRevField = regexp.MustCompile(`(?m)^result_rev=([^\s]+)\s*$`)
3122	var reReviewerIndexField = regexp.MustCompile(`(?m)^reviewer_index=([0-9]+)\s*$`)
3123	
3124	// CountPriorReviewErrors returns the number of `review-error` events already
3125	// recorded against this bead whose body cites the given result_rev. This is
3126	// the FEAT-022 §14 retry counter — it is event-scoped (no separate counter
3127	// field on the bead) so a fresh result_rev naturally resets the count.
3128	func CountPriorReviewErrors(store ExecuteBeadLoopStore, beadID, resultRev string) int {
3129		if resultRev == "" {
3130			return 0
3131		}
3132		events, err := store.Events(beadID)
3133		if err != nil {
3134			return 0
3135		}
3136		n := 0
3137		for _, ev := range events {
3138			if ev.Kind != "review-error" {
3139				continue
3140			}
3141			m := reResultRevField.FindStringSubmatch(ev.Body)
3142			if m == nil {
3143				continue
3144			}
3145			if m[1] == resultRev {
3146				n++
3147			}
3148		}
3149		return n
3150	}
