3152	// CountPriorReviewErrorsForSlot is the two-slot review-group retry counter.
3153	// It scopes retry budget to the candidate result_rev and reviewer slot so a
3154	// malformed/empty/transport failure in one slot does not consume the other
3155	// slot's retry allowance.
3156	func CountPriorReviewErrorsForSlot(store ExecuteBeadLoopStore, beadID, resultRev string, reviewerIndex int) int {
3157		if resultRev == "" {
3158			return 0
3159		}
3160		events, err := store.Events(beadID)
3161		if err != nil {
3162			return 0
3163		}
3164		wantIndex := fmt.Sprintf("%d", reviewerIndex)
3165		n := 0
3166		for _, ev := range events {
3167			if ev.Kind != "review-error" {
3168				continue
3169			}
3170			rev := reResultRevField.FindStringSubmatch(ev.Body)
3171			if rev == nil || rev[1] != resultRev {
3172				continue
3173			}
3174			idx := reReviewerIndexField.FindStringSubmatch(ev.Body)
3175			if idx == nil || idx[1] != wantIndex {
3176				continue
3177			}
3178			n++
3179		}
3180		return n
3181	}
