53	// RenderReviewPrompt assembles a structured review-session prompt with
54	// pinned sections first, then rolling session memory, then unresolved
55	// findings.
56	func RenderReviewPrompt(input ReviewPromptRenderInput) (ReviewPromptRenderResult, error) {
57		max := input.MaxPromptBytes
58		if max <= 0 {
59			max = evidence.DefaultMaxPromptBytes
60		}
61	
62		pinned := renderPinnedReviewPrompt(input)
63		if len(pinned) > max {
64			return ReviewPromptRenderResult{}, &PromptBudgetExceededError{
65				ObservedBytes: len(pinned),
66				CapBytes:      max,
67			}
68		}
69	
70		rolling := renderRollingReviewPrompt(input)
71		unresolved := renderUnresolvedFindingsPrompt(input.UnresolvedFindings)
72	
73		assembled := evidence.AssembleInline([]evidence.SectionInput{
74			{
75				Name:     "pinned",
76				Content:  pinned,
77				MinFloor: true,
78			},
79			{
80				Name:    "rolling",
81				Content: rolling,
82			},
83			{
84				Name:    "unresolved-findings",
85				Content: unresolved,
86			},
87		}, max)
88	
89		return ReviewPromptRenderResult{
90			Prompt:   assembled.Prompt,
91			Overflow: assembled.Overflow,
92			Sections: assembled.Sections,
93		}, nil
94	}
