160	func renderRollingReviewPrompt(input ReviewPromptRenderInput) string {
161		var sb strings.Builder
162		sb.WriteString("<rolling>\n")
163	
164		sb.WriteString("  <session-memory-summary>\n")
165		summary := strings.TrimSpace(input.SessionMemorySummary)
166		if summary == "" {
167			summary = defaultSessionMemorySummary(input.Session)
168		}
169		if summary == "" {
170			sb.WriteString("    <empty/>\n")
171		} else {
172			sb.WriteString("    ")
173			sb.WriteString(html.EscapeString(summary))
174			sb.WriteString("\n")
175		}
176		sb.WriteString("  </session-memory-summary>\n")
177	
178		turns := input.Session.Turns
179		limit := input.LastVerbatimTurns
180		if limit <= 0 || limit > len(turns) {
181			limit = len(turns)
182		}
183		sb.WriteString("  <last-verbatim-turns>\n")
184		if limit == 0 {
185			sb.WriteString("    <empty/>\n")
186		} else {
187			start := len(turns) - limit
188			for _, turn := range turns[start:] {
189				fmt.Fprintf(&sb, "    <turn actor=%q>\n", html.EscapeString(turn.Actor))
190				if strings.TrimSpace(turn.Content) == "" {
191					sb.WriteString("      <empty/>\n")
192				} else {
193					sb.WriteString("      ")
194					sb.WriteString(html.EscapeString(strings.TrimSpace(turn.Content)))
195					sb.WriteString("\n")
196				}
197				sb.WriteString("    </turn>\n")
198			}
199		}
200		sb.WriteString("  </last-verbatim-turns>\n")
201	
202		sb.WriteString("</rolling>\n")
203		return sb.String()
204	}
