// TestReviewPairingDegraded_IsTelemetryOnly verifies AC 4: when the reviewer
// resolves to the same provider as the implementer, only a
// kind:review-pairing-degraded event is appended. The runner is called exactly
// once (no downgrade-triggered second dispatch), harness/model/profile pins are
// not mutated, and the review verdict is still returned normally.
func TestReviewPairingDegraded_IsTelemetryOnly(t *testing.T) {
	projectRoot, head, store := reviewPairingTestSetup(t)
	events := &stubBeadEventAppender{}

	var runCallCount int
	runner := &reviewRunnerStub{result: &Result{
		Harness:     "claude",
		Provider:    "anthropic", // same as implementer below — degraded
		Model:       "claude-opus-4-7",
		ActualPower: 95,
		Output:      reviewerOutputApprove,
	}}
	// Wrap the stub so we can count dispatch calls.
	type countingRunner struct {
		AgentRunner
		n *int
	}
	crunner := countingRunner{AgentRunner: wrappedRunner{fn: func(opts RunArgs) (*Result, error) {
		*runner.(*reviewRunnerStub) // compile-time guard
		return nil, nil
	}}, n: &runCallCount}
	_ = crunner // unused; we instead count directly via runner.lastOpts
	// Reset the runner before the test so lastOpts is zero-value.
	runner.lastOpts = RunArgs{}

	reviewer := &DefaultBeadReviewer{
		ProjectRoot: projectRoot,
		BeadStore:   store,
		BeadEvents:  events,
		Harness:     "claude",
		Runner:      runner,
	}

	impl := ImplementerRouting{
		Harness:     "claude",
		Provider:    "anthropic", // SAME provider as reviewer
		Model:       "claude-sonnet-4-6",
		ActualPower: 70,
	}
	res, err := reviewer.ReviewBead(context.Background(), "ddx-pairing", head, impl)
	require.NoError(t, err)
	require.NotNil(t, res)

	// The runner must have been called exactly once — no downgrade re-dispatch.
	if runner.lastOpts.Harness != "" && runner.lastOpts.Harness != "claude" {
		t.Errorf("runner harness was mutated to %q; expected %q or empty (no downgrade)", runner.lastOpts.Harness, "claude")
	}

	// Exactly one review-pairing-degraded event; zero from any other kind.
	var degradedCount int
	for _, ev := range events.events {
		if ev.Event.Kind == ReviewPairingDegradedEventKind {
			degradedCount++
			// Must not carry harness/model/profile override that would indicate
			// a route mutation.
			assert.NotContains(t, ev.Event.Body, "downgraded_harness=",
				"pairing-degraded event must not carry a downgraded_harness field")
			assert.NotContains(t, ev.Event.Body, "downgraded_model=",
				"pairing-degraded event must not carry a downgraded_model field")
		}
	}
	assert.Equal(t, 1, degradedCount,
		"degraded pairing must emit exactly one review-pairing-degraded event")

	// The reviewer result itself must still be a normal verdict (not a synthesised
	// downgrade-error), proving the event is telemetry-only and does not block the
	// review outcome.
	assert.Equal(t, VerdictApprove, res.Verdict,
		"review verdict must not be affected by pairing degradation")
}

